// Associe chaque jour de la semaine à un angle éditorial
// Lundi=money, Mercredi=tools, Vendredi=pme
const DAY_TO_ANGLE = { 1: 'money', 3: 'tools', 5: 'pme' };
const DAY_LABELS = ['Dimanche','Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi'];
const now = new Date();
const jour = now.getDay();
const angle = DAY_TO_ANGLE[jour];
if (!angle) throw new Error('Pas de publication prévue aujourd\'hui (jour ' + jour + ')');
return [{ json: { angle, jour: DAY_LABELS[jour], date: now.toISOString().split('T')[0] } }];

const sujets = $input.first().json;
const angleData = $('Code — Détermine angle du jour').item.json;

const FORMAT_PROMPTS = {
  'Erreur + Solution': 'Slide 1 = problème choquant. Slides 2-6 alternent erreur courte et solution courte. Slide 7 = règle d\'or. Slide 8 = CTA.',
  'Avant / Après': 'Slide 1 = situation AVANT. Slide 2 = APRÈS. Slides 3-7 = étapes. Slide 8 = CTA.',
  'Chiffres qui choquent': 'Slide 1 = chiffre le plus impactant. Slides 2-6 = 1 chiffre + explication. Slide 7 = signification. Slide 8 = CTA.',
  'Checklist': 'Slide 1 = promesse. Slides 2-7 = 1 item actionnable. Slide 8 = CTA.',
  'Tutoriel': 'Slide 1 = résultat final. Slides 2-7 = étapes numérotées. Slide 8 = CTA.',
  'Concept simplifié': 'Slide 1 = définition. Slide 2 = problème résolu. Slides 3-5 = cas concrets. Slide 6 = quand NE PAS utiliser. Slide 7 = résumé. Slide 8 = CTA.'
};

if (Array.isArray(sujets) && sujets.length > 0) {
  const sujet = sujets[Math.floor(Math.random() * sujets.length)];
  return [{ json: {
    sujet_id: sujet.id,
    sujet: sujet.sujet,
    hook: sujet.hook || '',
    angle: sujet.angle,
    format: sujet.format,
    format_instructions: FORMAT_PROMPTS[sujet.format] || '',
    jour: angleData.jour,
    date: angleData.date,
    nb_slides: 8,
    nb_disponibles: sujets.length,
    cycle_reset: false
  }}];
}

// Tous les sujets épuisés → signal recyclage automatique
return [{ json: {
  sujet_id: null, sujet: null,
  angle: angleData.angle, jour: angleData.jour, date: angleData.date,
  nb_slides: 8, nb_disponibles: 0, cycle_reset: true
}}];

const raw = $input.first().json;
let text = '';
try { text = raw.candidates[0].content.parts[0].text; } catch(e) { throw new Error('Réponse Gemini invalide'); }
text = text.replace(/```json/gi, '').replace(/```/g, '').trim();
let data;
try { data = JSON.parse(text); } catch(e) { throw new Error('JSON parse error: ' + text.substring(0, 200)); }
if (!data.slides || !Array.isArray(data.slides) || data.slides.length === 0) throw new Error('Pas de slides dans la réponse');
const topicData = $('Merge — Sujet final').item.json;
return [{ json: {
  ...data,
  sujet_original: topicData.sujet,
  angle: topicData.angle,
  format: topicData.format,
  nb_slides_generes: data.slides.length,
  post_linkedin: data.post_linkedin || '',
  slides: data.slides.map((slide, i) => ({
    numero: slide.numero || (i + 1),
    titre: slide.titre || '',
    corps: slide.corps || '',
    prompt_image: slide.prompt_image || `Educational carousel slide. Beige #FAF7F2. Bold title: "${slide.titre}". Red accent #D72638. 1:1 square.`,
    filename: `TGM_slide_${String(slide.numero || (i+1)).padStart(2, '0')}.png`
  }))
}}];

const falResponse = $input.first().json;
const slideData = $('Split — 1 item par slide').item.json.slide;
const imageUrl = falResponse?.images?.[0]?.url || falResponse?.image?.url || null;
if (!imageUrl) throw new Error(`Pas d'URL image pour slide ${slideData.numero}`);
return [{ json: { image_url: imageUrl, slide_numero: slideData.numero, slide_titre: slideData.titre, filename: slideData.filename } }];
